config.script:
itemPath = [int(x) for x in list(event.itemPath)]
items = self.props.items
target = self.props.selectionData[0].value.target
lastSelection = [int(x) for x in list(self.custom.lastSelection)]
itemsCopy = system.util.jsonDecode(system.util.jsonEncode(items))
def toggleItemsByPath(items, path):
	current_level = items
	# Traverse down the levels to find the target node by following the path
	for i, index in enumerate(path):
		if i == len(path)-1:
			current_level = current_level[index]
		else:
			current_level = current_level[index]['items']
	# Recursively collapse all children within this node
	def recursiveCollapse(node):
		if 'items' in node:
			node['expanded'] = False
			for child in node['items']:
				recursiveCollapse(child)

	expand = not current_level['expanded']
	if not expand and itemPath != lastSelection and target != "":
		pass
	else:
		current_level['expanded'] = expand

	if not expand:
		for child in current_level['items']:
			recursiveCollapse(child)
if target != "":
	system.perspective.navigate(target)
toggleItemsByPath(itemsCopy, itemPath)
self.props.items = itemsCopy
self.custom.lastSelection = itemPath
